        <br>

        <!-- Retired for now, but kept in place in case the homepage quote returns.
        <h3 id='welcomeQuote' style='color: transparent;'>Life is an endless adventure<br>into the unknown</h3>
        -->
        <div id='homeAsk' class='home-ask' style='color: transparent;'>
            <div class='home-ask-bar' @click='focusInput'>
                <svg class='home-ask-spark' viewBox='0 0 24 24' aria-hidden='true'><path d='M12 3 L13.5 9.5 L20 11 L13.5 12.5 L12 19 L10.5 12.5 L4 11 L10.5 9.5 Z'/></svg>
                <div class='home-ask-input-wrap'>
                    <input
                        ref='askInput'
                        type='text'
                        class='home-ask-input'
                        v-model='askText'
                        placeholder=''
                        aria-label='Ask this site anything about Henry'
                        @focus='askFocused = true'
                        @blur='askFocused = false'
                        @compositionstart='askComposing = true'
                        @compositionend='askComposing = false'
                        @keydown.enter='submitAsk($event)'
                    >
                    <transition v-if='showExamplePrompt' name='home-prompt-fade' mode='out-in'>
                        <span
                            :key='askPromptText'
                            class='home-ask-prompt'
                            aria-hidden='true'
                        >{{ askPromptText }}</span>
                    </transition>
                    <span
                        v-else-if='inputEmpty'
                        class='home-ask-prompt'
                        aria-hidden='true'
                    >{{ askPromptText }}</span>
                </div>
                <span class='home-ask-hint' aria-hidden='true'>&crarr;</span>
            </div>
            <div v-if='askAnswerText || askBusy || askError || askMapVisible' class='home-ask-result'>
                <p v-if='askAnswerText' class='home-ask-answer'>{{ askAnswerText }}</p>
                <p v-else-if='askBusy' class='home-ask-status'>{{ askStatus }}</p>
                <p v-else-if='askError' class='home-ask-status'>{{ askErrorText }}</p>

                <div v-if='homeCitedSources.length && !askBusy' class='home-ask-sources'>
                    <button
                        v-for='s in homeCitedSources'
                        :key='s.id'
                        class='home-ask-source'
                        @click='goSource(s)'
                    >{{ s.page }} › {{ s.title }}</button>
                </div>

                <div v-if='askMapVisible || askBusy' class='home-ask-map-shell'>
                    <EmbeddingMap
                        ref='homeAskMap'
                        class='home-ask-map'
                        compact
                        fit-stage
                        initial-view-mode='3d'
                        :show-controls='false'
                        :show-view-toggle='false'
                        :show-caption='false'
                        :show-hits='false'
                        :allow-navigation='homeAskMapNavigable'
                        @ready='syncHomeAskMap'
                    />
                </div>
            </div>
        </div>
        </article>
    </div>
</template>
  
<script>
    import EmbeddingMap from './EmbeddingMap.vue';
    import { askConfigured, askStream, askErrorMessage } from '../utils/askSite';
    import { ASK_SAMPLE_PROMPTS, HOME_ASK_INTRO_PROMPT } from '../utils/askPrompts';
    import { semanticTopK } from '../utils/semanticSearch';
    import {
        allAskContexts,
        citedSourcesFromAnswer,
        cleanAskContextText,
        sourceDisplayTitle,
        stripAnswerCitations,
    } from '../utils/askRetrieval';

    // Keep in sync with slugify() in scripts/build-search-index.mjs and SearchPalette.vue.
    function slugify(s) {
        return String(s)
            .replace(/<[^>]+>/g, '')
            .toLowerCase()
            .trim()
            .replace(/[^\w\s-]/g, '')
            .replace(/\s+/g, '-')
            .replace(/-+/g, '-')
            .slice(0, 80);
    }

    // Assign slug ids to the current page's headings / timeline titles, mirroring the
    // build-time extractor, so a source link can deep-link to its section.
    function assignAnchors() {
        const root = document.querySelector('.content-container');
        if (!root) return;
        const useEntries = !!root.querySelector('li.title');
        const els = useEntries ? root.querySelectorAll('li.title') : root.querySelectorAll('h2, h3');
        const seen = new Set();
        els.forEach((el) => {
            const base = slugify(el.textContent);
            if (!base) return;
            let slug = base;
            let n = 2;
            while (seen.has(slug)) slug = `${base}-${n++}`;
            seen.add(slug);
            el.id = slug;
        });
    }

    // Land on the entry's visual top, not the title: research/projects keep the date label
    // at the top (.timeline-event); education/experience keep the school/company logo at the
    // top (the entry <section>).
    function scrollTargetFor(el) {
        const te = el.closest('.timeline-event');
        if (te) return te;
        if (el.matches && el.matches('li.title')) {
            const sec = el.closest('section');
            if (sec) return sec;
        }
        return el;
    }

    // Module-level (not a component method) on purpose: clicking a source navigates away
    // and UNMOUNTS IndexPage, so any `this`-bound retry would die. These plain functions
    // keep retrying against the freshly-rendered page until the anchor exists.
    function scrollToAnchor(anchor, samePage, findAttempt = 0) {
        if (!anchor) {
            window.scrollTo({ top: 0, behavior: samePage ? 'smooth' : 'auto' });
            return;
        }
        assignAnchors();
        const el = document.getElementById(anchor);
        if (el) {
            const target = scrollTargetFor(el);
            // Coming from another page (the hero always does), scroll instantly and HOLD:
            // logos/figures load after the first scroll and shift the layout, and the router
            // resets new routes to top — holdAtTop re-snaps past both.
            target.scrollIntoView({ behavior: samePage ? 'smooth' : 'auto', block: 'start' });
            if (!samePage) holdAtTop(target);
            return;
        }
        if (findAttempt < 25) setTimeout(() => scrollToAnchor(anchor, samePage, findAttempt + 1), 120);
    }

    function holdAtTop(target) {
        let live = true;
        const reSnap = () => { if (live && target.isConnected) target.scrollIntoView({ behavior: 'auto', block: 'start' }); };
        const stop = () => {
            live = false;
            window.removeEventListener('wheel', stop);
            window.removeEventListener('touchstart', stop);
            window.removeEventListener('keydown', stop);
        };
        window.addEventListener('wheel', stop, { passive: true });
        window.addEventListener('touchstart', stop, { passive: true });
        window.addEventListener('keydown', stop);
        const root = document.querySelector('.content-container') || document;
        [...root.querySelectorAll('img')].filter((im) => !im.complete).forEach((im) => {
            im.addEventListener('load', reSnap, { once: true });
            im.addEventListener('error', reSnap, { once: true });
        });
        [150, 400, 800, 1300, 1900].forEach((t) => setTimeout(reSnap, t));
        setTimeout(stop, 2400);
    }

    const HOME_ASK_STORAGE_KEY = 'homeAskState:v1';
    let homeAskMemory = null;

    function compactAskSources(sources) {
        return (sources || []).map((s) => ({
            id: s.id,
            route: s.route,
            anchor: s.anchor || '',
            page: s.page,
            title: s.title,
        }));
    }

    function readHomeAskState() {
        if (homeAskMemory) return homeAskMemory;
        if (typeof window === 'undefined' || !window.sessionStorage) return null;
        try {
            const raw = window.sessionStorage.getItem(HOME_ASK_STORAGE_KEY);
            homeAskMemory = raw ? JSON.parse(raw) : null;
            return homeAskMemory;
        } catch (err) {
            return null;
        }
    }

    function writeHomeAskState(state) {
        homeAskMemory = state;
        if (typeof window === 'undefined' || !window.sessionStorage) return;
        try {
            window.sessionStorage.setItem(HOME_ASK_STORAGE_KEY, JSON.stringify(state));
        } catch (err) {
            // Storage can be unavailable in private modes; in-memory state still covers route switches.
        }
    }

    export default {
        name: 'IndexPage',
        components: { EmbeddingMap },
        data() {
            return {
                scriptModule: null,
                askText: '',
                askFocused: false,
                askComposing: false,
                askAnswer: '',
                askSources: [],
                askBusy: false,
                askError: '',
                askStatus: '',
                askMapVisible: false,
                askMapHits: [],
                askMapLabel: '',
                askMapFinalized: false,
                askIntroPrompt: HOME_ASK_INTRO_PROMPT,
                askQuestions: ASK_SAMPLE_PROMPTS,
                askQIndex: -1,
                askRotate: null,
            };
        },
        computed: {
            // Idle: cycle through real example questions in a separate overlay so
            // each change can fade instead of snapping like a native placeholder.
            askPromptText() {
                if (this.askFocused) return 'Ask anything about Henry…';
                if (this.askQIndex < 0) return this.askIntroPrompt;
                return this.askQuestions[this.askQIndex];
            },
            // Treat an in-progress IME composition (pinyin not yet committed) as "not empty",
            // so the placeholder hides the moment the user starts typing — otherwise it stays
            // up and overlaps the characters being composed in the input.
            inputEmpty() {
                return !this.askText && !this.askComposing;
            },
            showExamplePrompt() {
                return !this.askFocused && this.inputEmpty;
            },
            askAnswerText() {
                return stripAnswerCitations(this.askAnswer);
            },
            homeCitedSources() {
                return citedSourcesFromAnswer(this.askAnswer, this.askSources);
            },
            askErrorText() {
                return askErrorMessage();
            },
            homeAskMapNavigable() {
                // Clickable once the request settles, whether it produced an answer
                // or errored out: the map still holds the retrieved passages, so the
                // visitor can jump into them even when generation failed.
                return !this.askBusy && (!!this.askAnswerText || !!this.askError);
            },
        },
        watch: {
            askText: 'persistHomeAskState',
            askAnswer: 'persistHomeAskState',
            askSources: {
                handler: 'persistHomeAskState',
                deep: true,
            },
            askError: 'persistHomeAskState',
            askStatus: 'persistHomeAskState',
            askMapVisible: 'persistHomeAskState',
            askMapHits: {
                handler: 'persistHomeAskState',
                deep: true,
            },
        },
        created() {
            this.restoreHomeAskState();
        },
        async mounted() {
            this._askSeq = 0;
            this._onHomeAskReady = this.startAskRotation;
            window.addEventListener('home-ask-ready', this._onHomeAskReady);
            // Dynamically import the script when the component is mounted
            this.scriptModule = await import('../assets/js/home.js');
            if (this.scriptModule && this.scriptModule.initScript) {
                this.scriptModule.initScript();
            }
        },
        unmounted() {
            // Clean up the script when the component is unmounted
            if (this.scriptModule && this.scriptModule.cleanupScript) {
                this.scriptModule.cleanupScript();
            }
            this.scriptModule = null; // Optionally, clear the reference to the module
            if (this._onHomeAskReady) window.removeEventListener('home-ask-ready', this._onHomeAskReady);
            if (this.askRotate) clearInterval(this.askRotate);
            if (this._homeAskMapFinalTimer) clearTimeout(this._homeAskMapFinalTimer);
            if (this.askBusy) {
                this.askBusy = false;
                this.askStatus = this.askAnswer ? '' : 'Paused.';
                this.persistHomeAskState();
            }
            this._askSeq += 1;
        },
        methods: {
            restoreHomeAskState() {
                // The root route (#/) is the fresh landing-home state. It should not
                // inherit a previously restored Ask/map result. Keep restoration only
                // for /home, which is the intentional return-from-another-tab state.
                if (this.$route.path === '/') return;

                const saved = readHomeAskState();
                if (!saved) return;
                this.askText = saved.askText || '';
                this.askAnswer = saved.askAnswer || '';
                this.askSources = Array.isArray(saved.askSources) ? saved.askSources : [];
                this.askError = saved.askError || '';
                this.askStatus = saved.askStatus || '';
                this.askMapVisible = !!saved.askMapVisible;
                this.askMapHits = Array.isArray(saved.askMapHits) ? saved.askMapHits : [];
                this.askMapLabel = saved.askMapLabel || '';
                this.askMapFinalized = !!saved.askMapFinalized;
            },
            persistHomeAskState() {
                writeHomeAskState({
                    askText: this.askText,
                    askAnswer: this.askAnswer,
                    askSources: compactAskSources(this.askSources),
                    askError: this.askError,
                    askStatus: this.askStatus,
                    askMapVisible: this.askMapVisible,
                    askMapHits: this.askMapHits,
                    askMapLabel: this.askMapLabel,
                    askMapFinalized: this.askMapFinalized,
                });
            },
            startAskRotation() {
                if (this.askRotate) return;
                this.askRotate = setInterval(() => {
                    if (!this.askFocused && !this.askText) {
                        this.askQIndex = this.nextRandomAskIndex();
                    }
                }, 3600);
            },
            nextRandomAskIndex() {
                const count = this.askQuestions.length;
                if (count <= 1) return this.askQIndex < 0 ? 0 : this.askQIndex;

                if (this.askQIndex < 0) {
                    return Math.floor(Math.random() * count);
                }

                let next = Math.floor(Math.random() * (count - 1));
                if (next >= this.askQIndex) next += 1;
                return next;
            },
            focusInput() {
                if (this.$refs.askInput) this.$refs.askInput.focus();
            },
            submitAsk(e) {
                if (this.askComposing || (e && e.isComposing)) return; // let IME commit first
                this.askHome(this.askText.trim());
            },
            async askHome(text) {
                const question = String(text || '').trim();
                if (!question || !askConfigured()) return;
                const seq = ++this._askSeq;
                this.askBusy = true;
                this.askError = '';
                this.askAnswer = '';
                this.askSources = [];
                this.askMapVisible = true;
                this.askMapHits = [];
                this.askMapLabel = question;
                this.askMapFinalized = false;
                this.$nextTick(() => this.prepareHomeAskMap(question, seq));

                try {
                    this.askStatus = 'Thinking…';
                    // Keep all regular site context, then add fragment chunks retrieved for this question.
                    const contexts = await allAskContexts(question);
                    if (seq !== this._askSeq) return;
                    this.askSources = contexts;
                    const payload = contexts.map(c => ({
                        page: c.page,
                        title: sourceDisplayTitle(c),
                        text: cleanAskContextText(c.body),
                    }));
                    for await (const tok of askStream(question, payload)) {
                        if (seq !== this._askSeq) return;
                        this.askAnswer += tok;
                    }
                    if (seq === this._askSeq) this.finishHomeAskMap();
                } catch (err) {
                    if (seq === this._askSeq) this.askError = 'error';
                    console.error('home ask failed:', err);
                } finally {
                    if (seq === this._askSeq) this.askBusy = false;
                }
            },
            async prepareHomeAskMap(question, seq) {
                try {
                    const hits = await semanticTopK(question, 8);
                    if (seq !== this._askSeq) return;
                    this.askMapHits = hits.map((h) => ({ id: h.id, score: h.score }));
                    this.askMapLabel = question;
                    const map = this.$refs.homeAskMap;
                    if (map && map.showExternalHits) {
                        // While waiting for the answer: keep the full map in view and just
                        // light up the retrieved passages, no zoom-in yet.
                        map.showExternalHits(this.askMapHits, {
                            label: question,
                            focus: false,
                            keepCentered: false,
                            duration: 900,
                        });
                    }
                } catch (err) {
                    console.warn('home ask map failed:', err);
                }
            },
            citedSourceItems() {
                const cited = new Set();
                const re = /\[([\d,\s]+)\]/g;
                let m;
                while ((m = re.exec(this.askAnswer))) {
                    m[1].split(/[\s,]+/).filter(Boolean).forEach((n) => cited.add(parseInt(n, 10)));
                }
                return this.askSources.filter((source, i) => cited.has(i + 1) && source && source.id != null);
            },
            finishHomeAskMap() {
                const hits = this.citedSourceItems().map((source) => ({ id: source.id, score: 0.92 }));
                this.askMapHits = hits;
                this.askMapLabel = hits.length ? 'cited passages' : this.askMapLabel;
                this.askMapFinalized = true;
                const map = this.$refs.homeAskMap;
                if (!map || !map.showExternalHits) return;
                if (this._homeAskMapFinalTimer) clearTimeout(this._homeAskMapFinalTimer);
                // Answer is in: zoom in onto the cited passages. (With no citations the
                // hit list is empty and the map falls back to the full view.)
                map.showExternalHits(hits, {
                    label: this.askMapLabel,
                    focus: true,
                    keepCentered: true,
                    duration: 850,
                });
            },
            syncHomeAskMap() {
                const map = this.$refs.homeAskMap;
                if (!map || !map.showExternalHits || !this.askMapHits.length) return;
                map.showExternalHits(this.askMapHits, {
                    label: this.askMapLabel,
                    // Full map until the answer is finalized, then focus on the cited passages.
                    focus: this.askMapFinalized,
                    keepCentered: this.askMapFinalized,
                    duration: 500,
                });
            },
            goSource(source) {
                if (!source) return;
                // Start the (module-level, unmount-proof) retry immediately, like the palette.
                // Fragment anchors must be written into the route so FragmentsTab can switch
                // from ideas to life before the scroll attempt.
                const samePage = this.$route.path === source.route;
                const isFragmentAnchor = source.route === '/fragments' && source.anchor;

                if (isFragmentAnchor) {
                    this.$router.push({ path: source.route, hash: `#${source.anchor}` }).catch(() => {});
                } else if (!samePage) {
                    this.$router.push(source.route).catch(() => {});
                }

                scrollToAnchor(source.anchor, samePage);
            },
        },
    }
</script>
 
